mapper.select:
/* FAQ 목록 조회 */ select a.faq_idx, a.question, a.answer, b.faq_cate_idx, b.faq_cate_name from tb_faq a, tb_faq_category b where a.faq_cate_idx = b.faq_cate_idx and a.del_yn = 'N'
and a.faq_cate_idx = #{cateIdx}
and (a.question like concat('%', #{search}, '%') or a.answer like concat('%', #{search}, '%'))
order by a.reg_date desc

mapper.insert:
/* FAQ 등록 */ insert into tb_faq (
faq_cate_idx, /* 카테고리식별자 */ question, /* 질문 */ answer, /* 답변 */ del_yn, /* 삭제여부(Y:예,N:아니오) */ reg_uid, /* 등록자ID */ reg_date /* 등록일시 */ ) values (
#{faqCateIdx }, #{question }, #{answer }, 'N', #{reg_uid }, now() )
